import csv
import sys

def read_csv(path):
    with open(path) as f:
        reader = csv.DictReader(f)
        return [row for row in reader]

def merge_rows(row_a, row_b):
    merged = {}
    for k, v in zip(row_a.keys(), row_a.values()):
        merged[k] = v
    for k, v in zip(row_b.keys(), row_b.values()):
        if k not in merged:
            merged[k] = v
    return merged

def main(path_a, path_b, output):
    rows_a = read_csv(path_a)
    rows_b = read_csv(path_b)
    with open(output, 'w', newline='') as f:
        writer = csv.DictWriter(f, fieldnames=rows_a[0].keys() | rows_b[0].keys())
        writer.writeheader()
        for a, b in zip(rows_a, rows_b):
            writer.writerow(merge_rows(a, b))

